Material.Shader:

/* This is a vertex program for ...
 */

attribute vec3 scalarsattrib;
varying float setScalar;

void main()
{
  /* Transform the normal. */
  vec3 lightDirection = scalarsattrib;// vec3(1.0, 0.6, 0.2);
  setScalar = dot(normalize(lightDirection),gl_Normal); // range [-1 1]
  setScalar = (setScalar + 1.0) * 6.0; // range [0 12]
  if(lightDirection.z == 0.5)
  {
	setScalar = 0.0;
  }

  gl_Position = ftransform();
}




/* This is a fragment program ...
 */
varying float setScalar;

uniform vec4 Color0;
uniform vec4 Color1;

void main()
{
	int parity = setScalar;

	if(setScalar == 0.0)
	{
		gl_FragColor = vec4(1.0, 1.0, 0.0, 1.0);
	}
	else if( setScalar > 11.9)
	{
		gl_FragColor = vec4(1.0, 0.0, 1.0, 1.0);
	}
	else 
	{
		if(mod(parity,2) == 0)
			gl_FragColor = Color1;
		else
			gl_FragColor = Color0;
	}

}
